import { act, renderHook } from '@testing-library/react-hooks';
import { useSelector } from 'react-redux';
import { useInvoiceCashbackPermission } from '../../../../src/services/invoiceCashbackPermission/hooks/useInvoiceCashbackPermission';
import { useInvoiceCashbackPermissionStore } from '../../../../src/services/invoiceCashbackPermission/hooks/useInvoiceCashbackPermissionStore';
import { invoiceCashbackPermissionService } from '../../../../src/services/invoiceCashbackPermission/services';

jest.mock('../../../../src/services/invoiceCashbackPermission/services');
jest.mock('react-redux');
jest.mock(
  '../../../../src/services/invoiceCashbackPermission/hooks/useInvoiceCashbackPermissionStore'
);

const mockSetHasRedeemed = jest.fn();
const mockSetLoading = jest.fn();
const mockSetError = jest.fn();

describe('useInvoiceCashbackPermission', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    (useSelector as jest.Mock).mockReturnValue('123');
    (useInvoiceCashbackPermissionStore as unknown as jest.Mock).mockImplementation((selector) => {
      if (selector.toString().includes('invoiceCashbackPermissionActions')) {
        return {
          setHasRedeemed: mockSetHasRedeemed,
          setLoading: mockSetLoading,
          setError: mockSetError,
        };
      }
      return {
        hasRedeemed: null,
        isLoading: false,
        isError: false,
      };
    });
  });

  describe('checkHasRedeemed', () => {
    it('should call service and update store on success', async () => {
      (invoiceCashbackPermissionService.hasRedeemed as jest.Mock).mockResolvedValue(true);

      const { result } = renderHook(() => useInvoiceCashbackPermission());

      await act(async () => {
        const hasRedeemed = await result.current.checkHasRedeemed({ showLoading: true });
        expect(hasRedeemed).toBe(true);
      });

      expect(mockSetLoading).toHaveBeenCalledWith(true);
      expect(invoiceCashbackPermissionService.hasRedeemed).toHaveBeenCalledWith('123');
      expect(mockSetHasRedeemed).toHaveBeenCalledWith(true);
    });

    it('should handle error', async () => {
      (invoiceCashbackPermissionService.hasRedeemed as jest.Mock).mockRejectedValue(
        new Error('error')
      );

      const { result } = renderHook(() => useInvoiceCashbackPermission());

      await act(async () => {
        const hasRedeemed = await result.current.checkHasRedeemed({ showLoading: true });
        expect(hasRedeemed).toBe(false);
      });

      expect(mockSetLoading).toHaveBeenCalledWith(true);
      expect(mockSetError).toHaveBeenCalledWith(true);
    });

    it('should throw error if no accountId', async () => {
      (useSelector as jest.Mock).mockReturnValue(null);
      const { result } = renderHook(() => useInvoiceCashbackPermission());

      await expect(result.current.checkHasRedeemed()).rejects.toThrow(
        'Expected accountId to be defined.'
      );

      expect(invoiceCashbackPermissionService.hasRedeemed).not.toHaveBeenCalled();
    });
  });

  describe('markAsRedeemed', () => {
    it('should call service and update store on success', async () => {
      (invoiceCashbackPermissionService.markAsRedeemed as jest.Mock).mockResolvedValue(undefined);

      const { result } = renderHook(() => useInvoiceCashbackPermission());

      await act(async () => {
        const success = await result.current.markAsRedeemed();
        expect(success).toBe(true);
      });

      expect(invoiceCashbackPermissionService.markAsRedeemed).toHaveBeenCalledWith('123');
      expect(mockSetHasRedeemed).toHaveBeenCalledWith(true);
    });

    it('should return false on error', async () => {
      (invoiceCashbackPermissionService.markAsRedeemed as jest.Mock).mockRejectedValue(
        new Error('error')
      );

      const { result } = renderHook(() => useInvoiceCashbackPermission());

      await act(async () => {
        const success = await result.current.markAsRedeemed();
        expect(success).toBe(false);
      });
    });
  });
});

