import { render, RenderOptions } from '@testing-library/react-native';
import React, { ReactElement } from 'react';
import { DeepPartial } from 'redux';

import { TestProvider } from '../__mocks__/utils/test-provider';
import rootReducers from '../../src/redux/reducers';

export type RootReducers = DeepPartial<typeof rootReducers>;

const customRender = (
  ui: ReactElement,
  initialState?: RootReducers,
  options?: RenderOptions,
) => {
  return {
    ...render(ui, {
      wrapper: ({ children }) => (
        <TestProvider initialState={initialState}>{children}</TestProvider>
      ),
      ...options,
    }),
  };
};

export * from '@testing-library/react-native';

export { customRender as render };

