import React from 'react';
import { render } from '@testing-library/react-native';
import { useRoute, useNavigation } from '@react-navigation/native';
import { useRootStore } from '../../../src/store';
import LearnMoreRewardProgram from '../../../src/screens/LearnMoreRewardProgram';
import ApiError from '../../../src/atomic/organisms/ApiError';
import { TestProvider } from '../../__mocks__/utils/test-provider';

jest.mock('@react-navigation/native', () => ({
  useRoute: jest.fn(),
  useNavigation: jest.fn(),
  useNavigationState: jest.fn(() => 'LearnMoreRewardProgram'),
  useFocusEffect: jest.fn((callback) => callback()),
}));

jest.mock('../../../src/store', () => ({
  useRootStore: jest.fn((selector: any) => {
    if (typeof selector === 'function') {
      return selector({
        parameterPointsProgram: {
          data: undefined,
          isError: false,
          selectedCategory: undefined,
        },
      });
    }
    return {
      parameterPointsProgram: {
        data: undefined,
        isError: false,
        selectedCategory: undefined,
      },
    };
  }),
}));

jest.mock('../../../src/hooks/tracking', () => ({
  useScreenViewTracking: jest.fn(),
}));

jest.mock('~/constants/functions', () => ({
  eventSelectContent: jest.fn(),
  eventScreenViewV3: jest.fn(),
}));

jest.mock('react-native', () => {
  const RN = jest.requireActual('react-native');
  return {
    ...RN,
    useWindowDimensions: () => ({ width: 375, height: 812 }),
  };
});

describe('LearnMoreRewardProgram', () => {
  const mockGoBack = jest.fn();
  const mockNavigate = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
    (useNavigation as jest.Mock).mockReturnValue({
      goBack: mockGoBack,
      navigate: mockNavigate,
    });
  });

  it('should render ApiError when data is not available', () => {
    (useRoute as jest.Mock).mockReturnValue({
      params: {},
    });

    (useRootStore as unknown as jest.Mock).mockImplementation((selector: any) => {
      if (typeof selector === 'function') {
        return selector({
          parameterPointsProgram: {
            data: undefined,
            isError: false,
            selectedCategory: undefined,
          },
        });
      }
      return {
        parameterPointsProgram: {
          data: undefined,
          isError: false,
          selectedCategory: undefined,
        },
      };
    });

    const { UNSAFE_getByType } = render(
      <TestProvider>
        <LearnMoreRewardProgram />
      </TestProvider>
    );
    expect(UNSAFE_getByType(ApiError)).toBeTruthy();
  });

  it('should render ApiError when selectedCategory is not provided', () => {
    (useRoute as jest.Mock).mockReturnValue({
      params: {},
    });

    (useRootStore as unknown as jest.Mock).mockImplementation((selector: any) => {
      if (typeof selector === 'function') {
        return selector({
          parameterPointsProgram: {
            data: [],
            isError: false,
            selectedCategory: undefined,
          },
        });
      }
      return {
        parameterPointsProgram: {
          data: [],
          isError: false,
          selectedCategory: undefined,
        },
      };
    });

    const { UNSAFE_getByType } = render(
      <TestProvider>
        <LearnMoreRewardProgram />
      </TestProvider>
    );
    expect(UNSAFE_getByType(ApiError)).toBeTruthy();
  });

  it('should render ApiError when isError is true', () => {
    (useRoute as jest.Mock).mockReturnValue({
      params: {},
    });

    (useRootStore as unknown as jest.Mock).mockImplementation((selector: any) => {
      if (typeof selector === 'function') {
        return selector({
          parameterPointsProgram: {
            data: [],
            isError: true,
            selectedCategory: undefined,
          },
        });
      }
      return {
        parameterPointsProgram: {
          data: [],
          isError: true,
          selectedCategory: undefined,
        },
      };
    });

    const { UNSAFE_getByType } = render(
      <TestProvider>
        <LearnMoreRewardProgram />
      </TestProvider>
    );
    expect(UNSAFE_getByType(ApiError)).toBeTruthy();
  });

  it('should render LearnMoreRewardProgramView when data is available', () => {
    (useRoute as jest.Mock).mockReturnValue({
      params: {},
    });

    const mockSelectedCategory = {
      category: 'Pontos',
      value: {
        questions: [
          {
            question: 'Question 1',
            answer: 'Answer 1',
          },
        ],
        order: 1,
        icon: 'icon-benefits' as const,
      },
      dateCreated: '2024-01-01',
      status: 1,
      PK: 'pk1',
      dateUpdated: '2024-01-01',
    };

    (useRootStore as unknown as jest.Mock).mockImplementation((selector: any) => {
      if (typeof selector === 'function') {
        return selector({
          parameterPointsProgram: {
            data: [],
            isError: false,
            selectedCategory: mockSelectedCategory,
          },
        });
      }
      return {
        parameterPointsProgram: {
          data: [],
          isError: false,
          selectedCategory: mockSelectedCategory,
        },
      };
    });

    const { getByText } = render(
      <TestProvider>
        <LearnMoreRewardProgram />
      </TestProvider>
    );
    expect(getByText('Saiba mais')).toBeTruthy();
  });

  it('should map data correctly to accordion items', () => {
    (useRoute as jest.Mock).mockReturnValue({
      params: {},
    });

    const mockSelectedCategory = {
      category: 'Pontos',
      value: {
        questions: [
          {
            question: 'Question 1',
            answer: 'Answer 1',
          },
          {
            question: 'Question 2',
            answer: 'Answer 2',
          },
        ],
        order: 1,
        icon: 'icon-benefits' as const,
      },
      dateCreated: '2024-01-01',
      status: 1,
      PK: 'pk1',
      dateUpdated: '2024-01-01',
    };

    (useRootStore as jest.Mock).mockImplementation((selector: any) => {
      if (typeof selector === 'function') {
        return selector({
          parameterPointsProgram: {
            data: [],
            isError: false,
            selectedCategory: mockSelectedCategory,
          },
        });
      }
      return {
        parameterPointsProgram: {
          data: [],
          isError: false,
          selectedCategory: mockSelectedCategory,
        },
      };
    });

    const { getByText } = render(
      <TestProvider>
        <LearnMoreRewardProgram />
      </TestProvider>
    );
    expect(getByText('Question 1')).toBeTruthy();
    expect(getByText('Question 2')).toBeTruthy();
  });
});

